module RefModule
(
  input          clock,
  input          reset,
  input   [7:0] a,
  input   [7:0] b,
  output [7:0]  sum
);

  reg [8:0] sum_reg;

    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clock or posedge dbg_halt) begin
    if (reset) begin
      sum_reg <= 8'b0;
    end else begin
      sum_reg <= a + b;
    end
  end

  assign sum = sum_reg[7:0];

endmodule
